  "inlineSchema": "generator client {\n  provider = \"prisma-client-js\"\n}\n\ndatasource db {\n  provider = \"postgresql\"\n  url      = env(\"DATABASE_URL\")\n}\n\n// 🏢 TENANT - Restaurant\nmodel Restaurant {\n  id                 String             @id @default(uuid())\n  name               String\n  slug               String             @unique\n  address            String\n  phone              String\n  email              String\n  logoUrl            String?\n  primaryColor       String?            @default(\"#F97316\")\n  description        String?\n  subscriptionStatus SubscriptionStatus @default(TRIAL)\n  createdAt          DateTime           @default(now())\n  updatedAt          DateTime           @updatedAt\n\n  // Relations\n  users        User[]\n  categories   Category[]\n  dishes       Dish[]\n  orders       Order[]\n  reservations Reservation[]\n  reviews      Review[]\n  openingHours OpeningHours[]\n  subscription Subscription?\n\n  @@index([slug])\n  @@index([subscriptionStatus])\n}\n\nenum SubscriptionStatus {\n  TRIAL\n  ACTIVE\n  PAST_DUE\n  CANCELLED\n}\n\n// 👤 UTILISATEURS (RBAC)\nmodel User {\n  id            String    @id @default(uuid())\n  email         String    @unique\n  password      String\n  name          String?\n  role          UserRole  @default(CLIENT)\n  restaurantId  String?\n  emailVerified DateTime?\n  createdAt     DateTime  @default(now())\n  updatedAt     DateTime  @updatedAt\n\n  restaurant   Restaurant?   @relation(fields: [restaurantId], references: [id])\n  orders       Order[]\n  reservations Reservation[]\n}\n\nenum UserRole {\n  SUPER_ADMIN\n  ADMIN\n  STAFF\n  KITCHEN\n  CLIENT\n}\n\n// 🕐 HORAIRES D'OUVERTURE\nmodel OpeningHours {\n  id           String     @id @default(uuid())\n  restaurantId String\n  dayOfWeek    Int // 0-6 (Dimanche-Samedi)\n  openTime     String // \"11:30\"\n  closeTime    String // \"22:00\"\n  isClosed     Boolean    @default(false)\n  restaurant   Restaurant @relation(fields: [restaurantId], references: [id], onDelete: Cascade)\n\n  @@unique([restaurantId, dayOfWeek])\n}\n\n// 🍽 CATÉGORIES DE MENU\nmodel Category {\n  id           String     @id @default(uuid())\n  name         String\n  description  String?\n  sortOrder    Int        @default(0)\n  restaurantId String\n  restaurant   Restaurant @relation(fields: [restaurantId], references: [id], onDelete: Cascade)\n  dishes       Dish[]\n\n  @@index([restaurantId])\n}\n\n// 🍕 PLATS\nmodel Dish {\n  id           String   @id @default(uuid())\n  name         String\n  description  String?\n  price        Decimal  @db.Decimal(10, 2)\n  imageUrl     String?\n  isAvailable  Boolean  @default(true)\n  isSpicy      Boolean  @default(false)\n  isVegetarian Boolean  @default(false)\n  allergens    String[] @default([])\n  categoryId   String\n  restaurantId String\n  sortOrder    Int      @default(0)\n  createdAt    DateTime @default(now())\n  updatedAt    DateTime @updatedAt\n\n  category   Category     @relation(fields: [categoryId], references: [id])\n  restaurant Restaurant   @relation(fields: [restaurantId], references: [id], onDelete: Cascade)\n  options    DishOption[]\n  orderItems OrderItem[]\n\n  @@index([restaurantId, categoryId])\n  @@index([isAvailable])\n}\n\n// 🧂 OPTIONS/MODIFIERS DE PLATS\nmodel DishOption {\n  id          String  @id @default(uuid())\n  dishId      String\n  name        String // \"Supplément fromage\"\n  price       Decimal @db.Decimal(10, 2)\n  isAvailable Boolean @default(true)\n  dish        Dish    @relation(fields: [dishId], references: [id], onDelete: Cascade)\n}\n\n// 🛒 COMMANDES\nmodel Order {\n  id                    String        @id @default(uuid())\n  restaurantId          String\n  userId                String?\n  status                OrderStatus   @default(PENDING)\n  type                  OrderType     @default(PICKUP)\n  totalPrice            Decimal       @db.Decimal(10, 2)\n  subtotal              Decimal       @db.Decimal(10, 2)\n  paymentMethod         PaymentMethod @default(ONLINE)\n  paymentStatus         PaymentStatus @default(PENDING)\n  stripePaymentIntentId String?\n  pickupTime            DateTime?\n  notes                 String?\n  customerName          String?\n  customerPhone         String?\n  customerEmail         String?\n  createdAt             DateTime      @default(now())\n  updatedAt             DateTime      @updatedAt\n\n  restaurant Restaurant  @relation(fields: [restaurantId], references: [id])\n  user       User?       @relation(fields: [userId], references: [id])\n  items      OrderItem[]\n\n  @@index([restaurantId, status])\n  @@index([createdAt])\n}\n\nenum OrderStatus {\n  PENDING\n  CONFIRMED\n  PREPARING\n  READY\n  COMPLETED\n  CANCELLED\n}\n\nenum OrderType {\n  PICKUP\n  DELIVERY\n  DINE_IN\n}\n\nenum PaymentMethod {\n  ONLINE\n  CASH\n  CARD_ON_SITE\n}\n\nenum PaymentStatus {\n  PENDING\n  PAID\n  FAILED\n  REFUNDED\n}\n\nmodel OrderItem {\n  id        String  @id @default(uuid())\n  orderId   String\n  dishId    String\n  quantity  Int\n  unitPrice Decimal @db.Decimal(10, 2)\n  options   Json? // [{\"name\": \"Supplément fromage\", \"price\": 1.00}]\n  notes     String? // \"Sans oignons\"\n\n  order Order @relation(fields: [orderId], references: [id], onDelete: Cascade)\n  dish  Dish  @relation(fields: [dishId], references: [id])\n}\n\n// 📅 RÉSERVATIONS\nmodel Reservation {\n  id           String            @id @default(uuid())\n  restaurantId String\n  userId       String?\n  name         String\n  email        String\n  phone        String\n  date         DateTime\n  time         String // \"19:30\"\n  guests       Int\n  status       ReservationStatus @default(PENDING)\n  notes        String?\n  tableNumber  String?\n  createdAt    DateTime          @default(now())\n  updatedAt    DateTime          @updatedAt\n\n  restaurant Restaurant @relation(fields: [restaurantId], references: [id])\n  user       User?      @relation(fields: [userId], references: [id])\n\n  @@index([restaurantId, date])\n  @@index([status])\n}\n\nenum ReservationStatus {\n  PENDING\n  CONFIRMED\n  CANCELLED\n  COMPLETED\n  NO_SHOW\n}\n\n// ⭐ AVIS CLIENTS\nmodel Review {\n  id           String   @id @default(uuid())\n  restaurantId String\n  orderId      String?\n  name         String\n  rating       Int // 1-5\n  comment      String?\n  isApproved   Boolean  @default(false)\n  createdAt    DateTime @default(now())\n\n  restaurant Restaurant @relation(fields: [restaurantId], references: [id])\n\n  @@index([restaurantId, isApproved])\n  @@index([rating])\n}\n\n// 💳 ABONNEMENTS\nmodel Subscription {\n  id                   String             @id @default(uuid())\n  restaurantId         String             @unique\n  stripeCustomerId     String?\n  stripeSubscriptionId String?\n  status               SubscriptionStatus\n  plan                 String             @default(\"STARTER\")\n  currentPeriodStart   DateTime?\n  currentPeriodEnd     DateTime?\n  createdAt            DateTime           @default(now())\n  updatedAt            DateTime           @updatedAt\n\n  restaurant Restaurant @relation(fields: [restaurantId], references: [id])\n}\n",
